class Solution {
    vector<vector<int>> res;
    vector<int> path;
    void dfs(vector<int>& a, int st) {
        res.push_back(path);
        for (int i=st;i<(int)a.size();i++) {
            if (i>st && a[i]==a[i-1]) continue;
            path.push_back(a[i]); dfs(a,i+1); path.pop_back();
        }
    }
public:
    vector<vector<int>> subsetsWithDup(vector<int>& nums) {
        sort(nums.begin(), nums.end()); dfs(nums,0); return res;
    }
};
